topp::~topp() {
    if (mVcdFile) 
        sc_close_vcd_trace_file(mVcdFile);

    mHdltvinHandle << "] " << endl;
    mHdltvoutHandle << "] " << endl;
    mHdltvinHandle.close();
    mHdltvoutHandle.close();
    delete conv1_U0;
    delete maxpool1_U0;
    delete conv2_U0;
    delete maxpool2_U0;
    delete conv3_U0;
    delete conv4_U0;
    delete conv5_U0;
    delete detection_head_U0;
    delete f1_U;
    delete p1_U;
    delete f2_U;
    delete p2_U;
    delete f3_U;
    delete f4_U;
    delete f5_U;
}

